import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"电动轮椅","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/0.无支线/电动轮椅.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/0.无支线/电动轮椅.md"}'),d={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/0.无支线/电动轮椅.md"};function p(l,a,_,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"电动轮椅",tabindex:"-1"},[s("电动轮椅 "),e("a",{class:"header-anchor",href:"#电动轮椅","aria-label":'Permalink to "电动轮椅"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),o('<h1 id="电动轮椅-1" tabindex="-1">电动轮椅 <a class="header-anchor" href="#电动轮椅-1" aria-label="Permalink to &quot;电动轮椅&quot;">​</a></h1><p>电动轮椅<br> 价格：250<br> 一台经过稍微改装的电动轮椅，使用起来并不比散步的速度快多少，但是整体采用了相当优异的人体工学设计及透气耐用的材质，因而坐在上面十分舒适，即使久坐移动也不会疲劳和损伤皮肤。同时，相比普通的轮椅，它的转向以及减震性能也更加优异，在一般轮椅无法使用的崎岖山路上也能如履平地，因此即使腿脚没问题也不妨碍拿它来代步。此外，轮椅扶手上也提供了多规格的充电口，可供各种小型电子设备如笔记本电脑或手机等充电，并能为它们提供额外的固定支架，在轮椅侧后方也各有额外的储物空间为使用者存放零食之类的东西。轮椅整体色调为白色纯色，风格较为干净整洁，但同时也可定制幻彩涂装或增加其他配饰。无论是想要清冷疏离的文弱感，还是展现飒爽利落的都市风格，它都能轻松贴合使用者的气质。</p><p>本质：科技本质<br> 载具类型：轻型载具<br> 载具专业：无<br> 速度：20米<br> 体积：4<br> 结构值：5<br> 装甲：0<br> 动力：电量可供持续移动8小时，可充电，晴天时则可以使用太阳能板充电，此时视为无限动力。<br> 载员情况：可供1名体型不大于6的使用者使用。</p><p>轮椅本身的可使用遥控器，扶手按键，亦或是使用者意念指令等方式遥控移动，因本身速度与步行差不多所以无需额外使用驾驶检定进行操控。但相应的这也意味着该载具不会在战斗中提供任何的防护和助力，在战斗中从轮椅中起身为一个迅捷动作。</p><p>此轮椅也可以由其他人帮助推行，此时移动速度取决于后面人能推多快。当然，你也可以选择自己手摇轮椅。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
